#define ETA 0.3f
#define MOMENTUM 0.3f

float squash(float x)
{
    return (1.0f / (1.0f + exp(-x)));
}

kernel void bpnn_layerforward_ocl(
    global float *input_units,
    global float *output_units,
    global float *weights,
    global float *partial_sum,
    local float *local_buf1,
    local float *local_buf2,
    const int n1,
    const int n2)
{
    int j = get_global_id(1);
    int block_id = get_global_id(0) / 16;
    int local_x = get_local_id(0);
    int local_y = get_local_id(1);

    if (j >= 1 && j <= n2) {
        float sum = 0.0f;

        for (int k = block_id * 16; k < (block_id + 1) * 16 && k <= n1; k++) {
            sum += weights[k * (n2 + 1) + j] * input_units[k];
        }

        partial_sum[block_id * n2 + j - 1] = sum;
    }
}

kernel void bpnn_adjust_weights_ocl(
    global float *delta,
    const int ndelta,
    global float *input_units,
    const int nly,
    global float *weights,
    global float *old_weights)
{
    int j = get_global_id(1);
    int k = get_global_id(0);

    if (j >= 1 && j <= ndelta && k <= nly) {
        float new_dw = (ETA * delta[j] * input_units[k]) + (MOMENTUM * old_weights[k * (ndelta + 1) + j]);
        weights[k * (ndelta + 1) + j] += new_dw;
        old_weights[k * (ndelta + 1) + j] = new_dw;
    }
}
